// --- Node-RED Function node: Decode & map Dragino uplink (PM5300) ---

const Dev = "ASSET_ID_START_MET_36";

// 1) Definitie van je kanalen en mapping (reg = (register-1) in hex, puur ter referentie)
var channels = [
    { prop: "total_system_power_W", reg: 0x0BF3, id: 4200 }, // reg 3060 (kW)
    { prop: "total_system_var_VAr", reg: 0x0BFB, id: 4300 }, // reg 3068 (kVAR)
    { prop: "total_export_kWh", reg: 0x0A8D, id: 4500 }, // reg 2702 (kWh) received/out of load
    { prop: "total_import_kWh", reg: 0x0A8B, id: 4600 }, // reg 2700 (kWh) delivered/into load
    { prop: "total_export_kVArh", reg: 0x0A95, id: 4700 }, // reg 2710 (kVARh) received
    { prop: "total_import_kVArh", reg: 0x0A93, id: 4800 }, // reg 2708 (kVARh) delivered
    { prop: "total_system_power_factor", reg: 0x0C0B, id: 4400 }, // reg 3084 (4Q FP PF)
];

// PM5300 levert kW/kVAR/kWh/kVARh al "proper" aan.
// Jij zei: DB is kW enz, maar propnaam heeft _W: dus NIET schalen.
var scaleBy1000 = []; // leeg

// 2) Decode Base64-payload naar Buffer
var buf = (typeof msg.payload === "string")
    ? Buffer.from(msg.payload, "base64")
    : msg.payload;

if (!Buffer.isBuffer(buf) || buf.length < 7) {
    node.error("Invalid payload", msg);
    return null;
}

// 3) Lees header en bepaal offset
var HEADER_LEN = 3;
var dataLen = buf.length - HEADER_LEN;
var floatCount = Math.floor(dataLen / 4);

// 4) Helper om een Big-Endian float32 te lezen en afronden
function readF(off) {
    if (off + 4 > buf.length) { return null; }
    var v = buf.readFloatBE(off);
    if (isNaN(v)) { return null; }
    return v;
}

// 4Q FP PF decode (Schneider PM53xx)
function decode4QPowerFactor(regVal) {
    if (regVal == null || isNaN(regVal)) return null;

    // Mapping vanuit Schneider "4Q FP PF"
    if (regVal > 1) return 2 - regVal;     // quadrant 4
    if (regVal < -1) return -2 - regVal;    // quadrant 2
    return regVal;                           // quadrant 1 & 3 + unity
}

// 5) Decode battery (bytes 0–1) en alle float-slots
var measurements = {
    battery: (((buf[0] << 8) | buf[1]) & 0x7fff) / 1000
};

for (var i = 0; i < floatCount && i < channels.length; i++) {
    var off = HEADER_LEN + i * 4;
    measurements[channels[i].prop] = readF(off);
}

// PF fix toepassen
if (measurements.total_system_power_factor != null) {
    measurements.total_system_power_factor = decode4QPowerFactor(measurements.total_system_power_factor);
}

// afronden (na PF decode)
Object.keys(measurements).forEach(function (k) {
    if (typeof measurements[k] === "number") {
        measurements[k] = Math.round(measurements[k] * 100) / 100;
    }
});

// 6) Bouw de standaardstructuur
var mid = global.get("mid") || 0;

var result = {
    MID: mid,
    D: [{
        Dev: Dev,
        TS: msg.time ? new Date(msg.time).toISOString() : undefined,
        ED: [],
        MD: []
    }]
};

// 7) Vul MD uit je kanaaltabel en het measurements-object
channels.forEach(function (ch) {
    var val = measurements[ch.prop];
    if (val != null) {
        // opschalen indien nodig (hier leeg gelaten)
        if (scaleBy1000.indexOf(ch.id) !== -1) {
            val = Math.round((val / 1000) * 1000) / 1000;
        }
        result.D[0].MD.push({ Id: ch.id, Val: val });
    }
});

// batterij
result.D[0].MD.push({ Id: 7200, Val: measurements.battery });

// 8) Optioneel: snr, rssi
[["snr", 5400], ["rssi", 5500]].forEach(function (item) {
    var key = item[0], id = item[1];
    if (msg[key] !== undefined) {
        result.D[0].MD.push({ Id: id, Val: parseFloat(msg[key]) });
    }
});

// spreadFactor uit msg.dr
if (msg.dr && msg.dr.spreadFactor !== undefined) {
    result.D[0].MD.push({ Id: 5200, Val: parseFloat(msg.dr.spreadFactor) });
}

// 9) Increment MID en return
global.set("mid", mid + 1);
msg.payload = result;
return msg;
